/// Returns the visible character width of a string by skipping ANSI CSI escape
/// sequences of the form `ESC [ ... m`.
fn strip_ansi_width(s: &str) -> usize {
    let bytes = s.as_bytes();
    let mut width = 0usize;
    let mut i = 0;
    while i < bytes.len() {
        if bytes[i] == b'\x1b' && bytes.get(i + 1) == Some(&b'[') {
            // Skip until the final byte of the escape sequence (a letter).
            i += 2;
            while i < bytes.len() && !bytes[i].is_ascii_alphabetic() {
                i += 1;
            }
            i += 1; // skip the terminating letter
        } else {
            // Count each non-escape byte as one visible character column.
            width += 1;
            i += 1;
        }
    }
    width
}

/// Print the ASCII art banner with `messages` alongside it — one message per
/// art line, starting from the first line.  Messages that extend beyond the
/// art line count are printed normally (at column 0) afterwards.
///
/// Everything is written to **stderr** so it interleaves correctly with the
/// logger output (which also goes to stderr).
pub fn print_banner_with_messages(messages: &[&str]) {
    let art_lines: Vec<&str> = ROCAS_ART.split('\n').collect();

    // Measure the visual width of the widest art line (should be 64).
    let art_width = art_lines
        .iter()
        .map(|l| strip_ansi_width(l))
        .max()
        .unwrap_or(0);

    let gap = "  ";

    let n = art_lines.len().max(messages.len());
    for i in 0..n {
        let art_line = art_lines.get(i).copied().unwrap_or("");
        let visible_w = strip_ansi_width(art_line);
        let padding = " ".repeat(art_width.saturating_sub(visible_w));

        if let Some(msg) = messages.get(i) {
            // Art line + padding to align + gap + log message.
            eprintln!("{art_line}{padding}{gap}{msg}");
        } else {
            eprintln!("{art_line}");
        }
    }
}

